mapper.select:
select coalesce(max(sequence_no), 0)
from agent_chat_message
where session_id = #{sessionId}

select id, session_id as sessionId, task_id as taskId, role, content, content_format as contentFormat, sequence_no as sequenceNo, create_time as createTime, update_time as updateTime, status, reserver, remark from agent_chat_message where session_id in
#{sid}
order by session_id, sequence_no asc limit 10000


select id, session_id as sessionId, task_id as taskId, role, content, content_format as contentFormat,
       sequence_no as sequenceNo, create_time as createTime, update_time as updateTime, status, reserver, remark
from agent_chat_message
where session_id = #{sessionId}
  and sequence_no < #{beforeSequenceNo}
order by sequence_no desc
limit #{size}
